INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Custom Themes$q$, $q$Restyle the entire Discord client with CSS-based themes, including support for transparent windows and community-made theme libraries.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Plugin System$q$, $q$A built-in plugin loader and JavaScript plugin API let users add new functionality, from message utilities to automation of status changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Live CSS Editor$q$, $q$Edit and preview CSS changes in real time without restarting the client, useful for building or debugging themes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Third-Party Emote Support$q$, $q$Use BTTV and FFZ emotes inside Discord chat when messaging other BetterDiscord users.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Developer Utilities$q$, $q$Exposes utility classes and a documented plugin API so developers can build and share their own plugins.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Community Theme and Plugin Directories$q$, $q$Official betterdiscord.app listings let users browse and one-click install community themes and plugins.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Cross-Platform Client Support$q$, $q$Works on the Windows, macOS, and Linux versions of the official Discord desktop app.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Large, active community of theme and plugin authors$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Deep interface customization beyond what official Discord offers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Source code is publicly auditable on GitHub$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Built-in tools like the live CSS editor make theme development easier$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Violates Discord's Terms of Service, which carries some risk of account action$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Not officially supported or endorsed by Discord$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Requires manual reinstallation or updates after some Discord client updates$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Plugin and theme quality and security vary since they are not reviewed by Discord$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Only works on desktop, not on Discord's mobile or web apps$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Is BetterDiscord free to use?$q$, $q$Yes. BetterDiscord is free and open source, with no subscription or paid tier for the core software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Is BetterDiscord against Discord's Terms of Service?$q$, $q$Yes. Discord has publicly stated that client modifications like BetterDiscord are against its Terms of Service because they alter the client outside of what Discord officially supports.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Will I get banned for using BetterDiscord?$q$, $q$Using BetterDiscord carries some risk of account action since it violates the Terms of Service, though enforcement has historically focused more on accounts using it for spam, automation, or abusive plugins rather than every installation. There is no guarantee either way.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$How do I install BetterDiscord?$q$, $q$Users download the official installer from betterdiscord.app, which patches the local Discord client files to add the BetterDiscord loader, themes menu, and plugin menu.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Does BetterDiscord work on mobile or the Discord web app?$q$, $q$No. BetterDiscord only works with the official Discord desktop application on Windows, macOS, and Linux.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$What is the difference between BetterDiscord and Vencord?$q$, $q$Both are Discord client mods with themes and plugins; Vencord is a separate, newer project with a different codebase and plugin format, and some tools bridge compatibility between the two ecosystems.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Who maintains BetterDiscord today?$q$, $q$The current codebase, maintained under the BetterDiscord GitHub organization, descends from a rewrite started by a developer known as Zerebos after earlier versions by the original creator, Jiiks, went dormant.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Can I write my own BetterDiscord plugin?$q$, $q$Yes. BetterDiscord exposes a documented plugin API and developer utility classes so anyone comfortable with JavaScript can build custom plugins.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Personal Discord Customization$q$, $q$Regular users install themes and plugins to change Discord's look and add small quality-of-life features.$q$, $q$Individual Discord users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Server Utility Enhancements$q$, $q$Server moderators and power users add plugins that provide extra client-side utilities not built into Discord.$q$, $q$Server moderators and community managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$Plugin and Theme Development$q$, $q$Developers use the plugin API and live CSS editor to build and share their own themes or plugins with the community.$q$, $q$Developers and theme authors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$BetterDiscord$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Custom themes","Plugin system","Live CSS editor","Community theme and plugin directories"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$overview$q$, $q$What Is BetterDiscord$q$, 2, ARRAY[$q$BetterDiscord is a free, open-source modification for the official Discord desktop client. Rather than being a separate app, it injects a loader into the existing Discord installation, giving users access to custom themes, community and self-made plugins, and interface options that Discord does not officially offer.$q$, $q$The project traces back to August 2015, when a developer known as Jiiks first built BetterDiscord. After periods of dormancy and a fork called BandagedBD maintained by a developer known as Zerebos, a rewrite started in 2020 became the codebase that ships today under the BetterDiscord GitHub organization.$q$, $q$Because it is entirely client-side and open source, anyone can inspect, modify, or contribute to the code. There is no company behind BetterDiscord and no paid tier; it is maintained by volunteer contributors and funded informally through donations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BetterDiscord's two main pillars are themes and plugins. Themes use CSS to restyle the entire Discord interface, including support for transparent or fully custom layouts, while plugins use JavaScript through a built-in plugin API to add new behavior, such as message utilities, status automation, or voice message sending.$q$, $q$The app also ships with a live CSS editor for real-time style debugging, developer-facing utility classes, and compatibility with third-party emote services like BTTV and FFZ so users can send extra emotes to other BetterDiscord users.$q$, $q$Because themes and plugins are community-submitted, quality and safety vary. BetterDiscord itself does not review third-party plugin code for malicious behavior, so users are expected to install plugins from sources they trust.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$BetterDiscord is completely free to download and use, and it will remain free since it is an open-source community project rather than a commercial product.$q$, $q$There are no subscription tiers, paid plugins sold by the core project, or in-app purchases. Some individual theme or plugin authors accept optional donations, but this is separate from BetterDiscord itself.$q$, $q$The only cost to consider is not financial but the standing-service risk: because BetterDiscord violates Discord's Terms of Service, using it carries some risk of account action from Discord, which functions as the real trade-off against its zero monetary price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('57e5cd5a-3371-4f98-94e6-bdba29cb1d89', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Automated Portfolio Management$q$, $q$Builds and continuously rebalances diversified ETF portfolios based on a customer's goals and risk tolerance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Tax-Loss Harvesting$q$, $q$Automatically sells losing positions to offset gains and reduce taxable income in eligible taxable accounts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Tax-Coordinated Portfolio$q$, $q$Places tax-inefficient assets into tax-advantaged accounts and tax-efficient assets into taxable accounts to reduce overall tax drag.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Human Advisor Access$q$, $q$Premium plan customers get unlimited access to Betterment's licensed financial advisors for planning guidance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Cash Management$q$, $q$Betterment Checking and a high-yield cash reserve account let customers manage everyday spending and savings alongside investments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Retirement Accounts$q$, $q$Supports traditional, Roth, and SEP IRAs as well as employer-sponsored 401(k) plans through Betterment at Work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Automated Crypto Investing$q$, $q$Offers automated cryptocurrency portfolios following Betterment's acquisition of Makara.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Goal-Based Planning Tools$q$, $q$In-app tools help customers set and track progress toward goals like retirement, a home purchase, or an emergency fund.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Lower fees than traditional human financial advisors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$No account minimum on the Digital plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Automatic rebalancing and tax-loss harvesting built in$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Wide range of account types, including checking, IRAs, and employer 401(k)s$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Access to licensed human advisors on the Premium plan$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Long operating history and SEC/FINRA regulatory oversight$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Premium plan requires a 100,000 dollar minimum balance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$0.65 percent Premium fee is higher than some robo-advisor competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Limited direct control over individual stock selection$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Cash account yields fluctuate with prevailing interest rates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Disclosed a data breach in January 2026 affecting some customer contact information$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$What is Betterment?$q$, $q$Betterment is a robo-advisor and SEC-registered investment advisor that offers automated investing, retirement accounts, and cash management for individual investors.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$How much does Betterment cost?$q$, $q$The Digital plan charges 0.25 percent of assets annually or 4 dollars per month for smaller balances, while the Premium plan charges 0.65 percent annually and requires a 100,000 dollar minimum.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Is Betterment safe and regulated?$q$, $q$Betterment LLC is registered as an investment advisor with the SEC, and its affiliate Betterment Securities is a FINRA-member broker-dealer, so customer accounts fall under standard securities industry regulation and SIPC coverage for the brokerage accounts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Does Betterment have a minimum investment?$q$, $q$The Digital plan has no account minimum. The Premium plan requires a 100,000 dollar minimum balance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$What is tax-loss harvesting?$q$, $q$It is an automated strategy where Betterment sells investments at a loss to offset taxable gains elsewhere in a customer's portfolio, potentially lowering their tax bill.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Can I talk to a human advisor at Betterment?$q$, $q$Yes, unlimited access to licensed financial advisors is included with the Premium plan; Digital plan customers can purchase one-off advice packages.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$How much does Betterment manage in assets?$q$, $q$As of mid-2026, Betterment reports managing more than 70 billion dollars in assets for over one million customers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Has Betterment had any security incidents?$q$, $q$In January 2026, Betterment disclosed a data breach exposing some customers' names, contact information, and dates of birth, along with related fraudulent crypto scam notifications; this is a publicly reported incident rather than an ongoing feature of the platform.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Hands-Off Retail Investing$q$, $q$Investors who want a diversified, automatically managed portfolio without picking individual stocks.$q$, $q$Individual retail investors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Retirement Savings$q$, $q$Savers use Betterment's traditional, Roth, or SEP IRAs to build long-term retirement portfolios with automated rebalancing.$q$, $q$Retirement savers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Employer-Sponsored Retirement Plans$q$, $q$Small and mid-sized businesses use Betterment at Work to offer employees a 401(k) plan without building one in-house.$q$, $q$Employers and HR teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Digital$q$, $q$0.25% annually or $4/month$q$, $q$Annual fee (AUM-based) or monthly flat fee$q$, NULL, $q$["No account minimum","Automated rebalancing","Tax-loss harvesting","Goal-based planning tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$Premium$q$, $q$0.65% annually$q$, $q$Annual fee (AUM-based)$q$, NULL, $q$["$100,000 minimum balance","Unlimited access to licensed financial advisors","Everything in Digital","Tax-coordinated portfolio"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$overview$q$, $q$What Is Betterment$q$, 2, ARRAY[$q$Betterment is an automated investing platform, founded in 2008 by Jon Stein and Eli Broverman and headquartered in New York City. It is widely credited as one of the earliest robo-advisors to bring algorithm-driven portfolio management to everyday retail investors.$q$, $q$Betterment LLC operates as a registered investment advisor with the SEC, and its affiliate Betterment Securities is a FINRA-member broker-dealer, which together provide the regulatory basis for holding and managing customer investment accounts.$q$, $q$As of mid-2026, Betterment manages more than 70 billion dollars in assets for over one million customers, spanning individual taxable accounts, retirement accounts, cash accounts, and employer-sponsored retirement plans.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Betterment builds diversified portfolios out of low-cost ETFs and automatically rebalances them as markets move or a customer's goals change. Tax-loss harvesting and tax-coordinated portfolio placement are available to help reduce the tax drag on taxable accounts.$q$, $q$The platform supports multiple account types, including individual and joint taxable accounts, traditional, Roth, and SEP IRAs, a high-yield cash reserve account, and Betterment Checking. Betterment at Work extends the platform to employers offering 401(k) plans to their staff.$q$, $q$Following its acquisition of Makara, Betterment also offers automated cryptocurrency investing portfolios, and the Premium plan adds ongoing access to a team of licensed human financial advisors for more complex financial planning needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('247d840a-2d7d-4990-8c6a-3e31760daf3d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Betterment's Digital plan charges 0.25 percent of assets under management annually, or a flat 4 dollars per month for accounts under 20,000 dollars that do not have recurring monthly deposits set up, with no minimum balance required to open an account.$q$, $q$The Premium plan charges 0.65 percent of assets annually, requires a 100,000 dollar minimum balance, and adds unlimited access to Betterment's team of certified financial planners for personalized advice.$q$, $q$Betterment at Work and advisor-facing products (Betterment Advisor Solutions) are priced separately and are typically negotiated with employers or advisory firms rather than sold at a fixed consumer rate.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$OKR and Goal Management$q$, $q$Cascade company objectives down to team and individual OKRs with real-time progress dashboards.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Continuous Feedback$q$, $q$Structured tools for ongoing, real-time feedback between managers and employees outside of formal review cycles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Performance Reviews$q$, $q$Configurable review cycles and conversation tools that tie back to goal progress and feedback history.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Calibration$q$, $q$Workflows that help managers and HR align performance ratings consistently across teams and departments.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Succession Planning$q$, $q$Tools for identifying and tracking succession candidates for key roles across the organization.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Skills Intelligence$q$, $q$AI-assisted analysis of employee skills to support development planning and workforce decisions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Manager 1-on-1 Tools$q$, $q$Built-in templates and tracking for recurring manager-employee check-in meetings.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$AI-Powered Insights$q$, $q$AI features that generate development plan suggestions and surface workforce trends for HR and leadership.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Combines OKRs, feedback, and formal reviews in one connected platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Strong calibration and succession planning features for enterprise HR teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$AI-assisted coaching and workforce insights$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Established vendor with a long operating history since 2013$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Integrates with common workplace tools like Slack, Teams, and HRIS systems$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$No self-serve signup, requiring a sales conversation for pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Best suited to organizations with 500 or more employees$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Higher cost than lightweight, OKR-only tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Enterprise tier pricing is fully custom and not published$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Implementation and rollout can require dedicated onboarding support$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$What is Betterworks used for?$q$, $q$Betterworks is used by enterprises to manage OKRs and goals, continuous feedback, performance reviews, calibration, and succession planning in one connected platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$How much does Betterworks cost?$q$, $q$Betterworks lists a Performance plan starting at 8 dollars per user per month and a Performance plus Talent Intelligence plan starting at 9 dollars per user per month, with a custom-priced Enterprise tier for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Is there a free trial or self-serve plan?$q$, $q$No. Betterworks does not offer self-serve signup; pricing and access require contacting sales.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$What size organization is Betterworks built for?$q$, $q$Betterworks is positioned primarily for mid-market and large enterprises, with the company noting organizations of 500 or more employees see the most value.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$When was Betterworks founded?$q$, $q$Betterworks was founded in 2013 and is headquartered in Menlo Park, California, with an additional office in New York City.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Does Betterworks include performance reviews, not just OKRs?$q$, $q$Yes. Betterworks combines OKR and goal tracking with continuous feedback, formal performance reviews, and calibration in a single platform.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Does Betterworks use AI?$q$, $q$Yes. Betterworks includes AI-assisted features for coaching suggestions, development plans, and workforce insights, particularly on its Talent Intelligence and Enterprise tiers.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Who are Betterworks' main competitors?$q$, $q$Betterworks competes with other performance management and OKR platforms such as Lattice, Culture Amp, and 15Five.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Enterprise OKR Alignment$q$, $q$Large organizations use Betterworks to cascade company strategy into team and individual OKRs with real-time tracking.$q$, $q$Enterprise leadership and People teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Connected Performance Reviews$q$, $q$HR teams tie goal progress and continuous feedback directly into structured performance review cycles.$q$, $q$HR and People operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Succession and Talent Planning$q$, $q$People analytics teams use calibration and succession planning tools to make consistent talent decisions across the company.$q$, $q$People analytics and talent management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Performance$q$, $q$$8/user/month$q$, $q$Per user, per month$q$, NULL, $q$["Goals and OKRs","Continuous feedback","Performance reviews","Manager 1-on-1 tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Performance + Talent Intelligence$q$, $q$$9/user/month$q$, $q$Per user, per month$q$, NULL, $q$["Everything in Performance","Calibration","Succession planning","Skills intelligence"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Everything in Performance + Talent Intelligence","Engagement and culture measurement","Dedicated implementation team","Change management services"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$overview$q$, $q$What Is Betterworks$q$, 2, ARRAY[$q$Betterworks is an enterprise performance management platform founded in 2013 and headquartered in Menlo Park, California. It was built around the idea of connecting OKR-based goal setting to the rest of the performance management cycle, including feedback, reviews, and talent decisions.$q$, $q$The platform was co-founded by Kris Duggan, who led the company as CEO in its early years before stepping away from day-to-day leadership in 2017; Betterworks has continued operating and expanding its product line since then.$q$, $q$Rather than functioning as a standalone OKR tracker, Betterworks combines goals and OKRs, continuous feedback, performance reviews, calibration, succession planning, and AI-powered workforce insights into a single connected system aimed at mid-market and large enterprises.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Betterworks is goal and OKR management, letting organizations cascade objectives from company strategy down to team and individual goals, with dashboards to track progress in real time.$q$, $q$The platform layers continuous feedback, structured 1-on-1 tools, and formal performance review cycles on top of goal tracking, so managers can connect day-to-day coaching conversations to formal review outcomes.$q$, $q$Higher tiers add talent intelligence features such as calibration workflows for consistent rating decisions across teams, succession planning, skills intelligence, and unified talent profiles, along with AI-assisted development plans and workforce insights.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('25a76d30-e9e5-4707-ae76-35af527f1879', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Betterworks sells three main plans, all priced per user per month: Performance, Performance plus Talent Intelligence, and a custom-quoted Enterprise tier.$q$, $q$The Performance plan starts at 8 dollars per user per month and covers OKR and goal tracking, feedback, review conversations, and manager 1-on-1 tools. The Performance plus Talent Intelligence plan starts at 9 dollars per user per month and adds calibration, succession planning, and skills intelligence.$q$, $q$The Enterprise plan is custom-priced and adds transformational program design, engagement and culture measurement, and a dedicated implementation team. There is no self-serve signup, and Betterworks positions its platform primarily for organizations with 500 or more employees.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Entity Component System$q$, $q$A parallel, cache-friendly ECS separates data (components) from behavior (systems) for modular, high-performance game logic.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$2D and 3D Rendering$q$, $q$Built-in rendering pipeline supports sprites, cameras, lighting, shadows, and glTF 3D model import.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Bevy UI Framework$q$, $q$A native, ECS-driven UI system with a flexbox-style layout model for building game and editor interfaces.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Cross-Platform Builds$q$, $q$Ships to Windows, macOS, Linux, and the web via WebAssembly from a single Rust codebase.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Hot Asset Reloading$q$, $q$Assets can be modified and reloaded while the app is running, speeding up iteration during development.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Plugin Architecture$q$, $q$Engine functionality is organized into modular plugins that can be added, removed, or replaced by third-party crates.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Fast Compile Times$q$, $q$The project prioritizes short iterative compile times relative to other Rust game development setups.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Open-Source, Dual-Licensed Code$q$, $q$Distributed under the MIT or Apache 2.0 license, free for personal and commercial use with no royalties.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Completely free and open source under MIT or Apache 2.0 licensing$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Fast, parallel ECS architecture designed for performance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Actively developed with frequent releases and a large community$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Memory-safe by virtue of being built in Rust$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Growing ecosystem of third-party plugin crates$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Backed in part by the nonprofit Bevy Foundation$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Still pre-1.0, with breaking API changes between minor versions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Smaller ecosystem and asset marketplace than Unity, Unreal, or Godot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Requires knowledge of Rust, which has a steeper learning curve than some scripting languages$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$No full built-in visual editor comparable to Unity or Unreal's editors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Documentation and tutorials can lag behind the engine's fast-moving API$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Is Bevy Engine free?$q$, $q$Yes. Bevy is free and open source under the MIT and Apache 2.0 licenses, with no fees or royalties for personal or commercial use.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$What programming language is Bevy written in?$q$, $q$Bevy is written in Rust, and games built with it are also written in Rust.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Does Bevy support both 2D and 3D games?$q$, $q$Yes. Bevy includes rendering support for both 2D sprites and 3D scenes with lighting, shadows, and glTF model import.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Is Bevy production ready?$q$, $q$Bevy is actively used for shipped games and tools, but as of its ongoing development it has not reached a 1.0 release, and its API can change between versions, which teams should plan for.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$What license does Bevy use?$q$, $q$Bevy is dual-licensed under the MIT and Apache 2.0 licenses, letting developers choose either license.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$How does Bevy compare to Unity or Godot?$q$, $q$Bevy uses Rust and a code-first ECS architecture rather than a visual editor-first workflow like Unity or Godot, and it has a smaller asset ecosystem but offers Rust's performance and memory safety.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Does Bevy have a visual editor?$q$, $q$Bevy does not yet ship a full built-in visual editor comparable to Unity or Unreal, though editor tooling is an active area of community development.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Who created Bevy Engine?$q$, $q$Bevy was created by developer Carter Anderson, who first released it publicly in August 2020, and it is now maintained by a broad open-source community.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Indie Game Development$q$, $q$Independent and hobbyist developers use Bevy to build 2D and 3D games with a modern ECS architecture at no licensing cost.$q$, $q$Indie and hobbyist game developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Rust Application Development$q$, $q$Rust developers use Bevy's ECS and rendering framework for interactive simulations and applications beyond traditional games.$q$, $q$Rust developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$Open-Source Game Projects$q$, $q$Open-source game projects choose Bevy for its permissive licensing and transparent, community-driven development process.$q$, $q$Open-source game project maintainers$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$overview$q$, $q$What Is Bevy Engine$q$, 2, ARRAY[$q$Bevy is a free, open-source game engine and application framework written entirely in Rust. It was created by developer Carter Anderson, with the project's first public release, version 0.1, launching on August 10, 2020.$q$, $q$The engine is described by its creators as refreshingly simple and data-driven, built around an Entity Component System (ECS) architecture rather than the object-oriented, inheritance-based design used by many older engines.$q$, $q$Bevy is maintained as an open-source project on GitHub under the bevyengine organization, with development supported in part by the nonprofit Bevy Foundation and a large community of volunteer contributors.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bevy's core is its ECS, where entities are lightweight IDs, components are pure data, and systems are functions that operate on that data; the scheduler runs independent systems in parallel automatically, which the project describes as massively parallel, cache-friendly, and fast.$q$, $q$The engine includes 2D and 3D rendering with support for sprites, cameras, lighting, shadows, and glTF model import, a native Bevy UI framework built on the same ECS principles with a flexbox-style layout model, and hot asset reloading so changes appear without restarting the app.$q$, $q$Bevy targets Windows, macOS, Linux, and the web through WebAssembly from a single codebase, and the project has invested heavily in fast compile times, with iterative build times reported as low as under a few seconds in optimized development configurations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bevy is completely free and open source, dual-licensed under the MIT and Apache 2.0 licenses. Developers can choose whichever license suits their project and use the engine for personal, commercial, or open-source games without paying fees or royalties.$q$, $q$There is no paid tier, editor license, or revenue-sharing requirement of any kind, which distinguishes Bevy from commercial engines like Unity or Unreal Engine that have licensing fees or royalty thresholds.$q$, $q$Because Bevy is community-funded through the nonprofit Bevy Foundation and direct sponsorships, users who want to support ongoing development can contribute financially, but doing so is entirely optional and not required to use the engine.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d53fd227-dfc9-4433-b23c-eae93cde107f', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Points-Based Subscription$q$, $q$Customers received a monthly allotment of points redeemable for standard or premium design deliverables.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Dedicated Account Manager$q$, $q$Each subscription included a named account manager who helped scope and prioritize design requests.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Points Rollover$q$, $q$Unused monthly points carried over, letting customers bank capacity for busier campaign periods.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Video Content Production$q$, $q$Design output included video assets for marketing and advertising campaigns.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Digital Advertisement Design$q$, $q$Produced digital ad creative for marketing teams running paid campaigns.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Website Design$q$, $q$Offered website design services as part of its broader creative deliverable catalog.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Tiered Subscription Plans$q$, $q$Offered Flexi 10 and Flexi 40 Plus tiers scaled to different volumes of monthly design output.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Avoided the cost of hiring and managing an in-house design team$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Points system allowed flexibility across different design deliverable types$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Dedicated account manager simplified project intake$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Unused points rolled over instead of being forfeited$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Covered a broad range of deliverables, including video, ads, and web design$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Exact subscription pricing was not publicly published$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Current operating status is unclear based on available public information$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$The primary bexi.io website no longer displays an active product presence as of this research$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Independent, recent customer reviews of the platform are limited$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Required an annual commitment even when paying monthly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$What did Bexi do?$q$, $q$Bexi was a design-subscription platform that gave marketing teams on-demand access to a creative production team for deliverables like video content, digital ads, and website design, in exchange for a monthly or annual subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Who founded Bexi?$q$, $q$Bexi was founded in August 2016 by Rafael Gomez and Cuco Vega, and was based in San Francisco with production offices in Mexico.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Is Bexi still active?$q$, $q$Based on this research, the bexi.io domain currently redirects to an unrelated personal website and its pricing page shows unpopulated template text, so its current operating status could not be confirmed from public sources.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$How did the Flexi points system work?$q$, $q$Customers received a set number of points each month based on their plan tier, redeemable for standard or premium design assets, with unused points rolling over to future months.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$What kind of design work did Bexi handle?$q$, $q$Bexi's team produced video content, digital advertisements, and website design for marketing teams, based on publicly available descriptions of the service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Did Bexi publish self-serve pricing?$q$, $q$No specific dollar pricing for the Flexi 10 or Flexi 40 Plus plans was found in public sources during this research; customers reportedly worked with an account manager to select a plan.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Marketing Team Creative Support$q$, $q$Marketing teams used Bexi to outsource ongoing design production without hiring additional in-house designers.$q$, $q$In-house marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Startup Brand Assets$q$, $q$Startups used the subscription model to get a steady supply of ad and web design assets while building out their brand.$q$, $q$Startup founders and marketers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Agency Overflow Capacity$q$, $q$Agencies reportedly used services like Bexi to add creative production capacity for client campaigns without hiring more staff.$q$, $q$Marketing and creative agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Flexi 10$q$, $q$Not publicly listed$q$, $q$Monthly or annual (annual commitment required)$q$, NULL, $q$["Monthly points allotment for one product or offering","Points rollover","Dedicated account manager"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$Flexi 40 Plus$q$, $q$Not publicly listed$q$, $q$Monthly or annual (annual commitment required)$q$, NULL, $q$["Higher monthly points allotment","Supports multiple products or brands","Points rollover","Dedicated account manager"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$overview$q$, $q$What Is Bexi$q$, 2, ARRAY[$q$Bexi was a design-subscription platform launched in August 2016 by Rafael Gomez and Cuco Vega, based in San Francisco with production offices in Mexico. It positioned itself as an alternative to hiring in-house designers or paying traditional agency retainers for marketing creative work.$q$, $q$The service targeted marketing teams at small and mid-sized businesses that needed an ongoing, flexible supply of design assets, such as digital ads, video content, and website design, without the overhead of building an internal creative team.$q$, $q$As of this research, the bexi.io domain no longer displays an active product site; it redirects to an unrelated personal website, and a pricing page on the domain shows unpopulated template text rather than published pricing, so the current operating status of the business is unclear from public sources.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Bexi's model centered on a points-based subscription: customers received a monthly allotment of points that could be redeemed for standard or premium design deliverables, giving them flexibility to request different types of assets within a single plan.$q$, $q$Each account was paired with a dedicated account manager who helped clients scope, prioritize, and open new design projects, functioning as the main point of contact between the customer and Bexi's production team.$q$, $q$Because unused points rolled over to the following month, customers could bank capacity during slower periods and use it during higher-volume campaign pushes, which was positioned as more flexible than a fixed-scope agency retainer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a41e74d-6972-4d0c-b2ac-9bc51b258ef6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Bexi offered at least two named subscription tiers, Flexi 10 and Flexi 40 Plus, differentiated by the volume of design points included each month, with Flexi 40 Plus aimed at customers managing multiple products or a higher volume of campaigns.$q$, $q$Plans required an annual commitment but gave customers the choice of paying monthly or paying upfront for a reported discount, according to third-party pricing pages associated with the Bexi brand.$q$, $q$Exact dollar pricing for each tier was not published in the sources available for this research, and the current pricing page on bexi.io does not display live pricing, so prospective customers should contact the company directly to confirm current rates and availability.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Character Interview Tool$q$, $q$A structured interview process helps authors develop each character in depth before and during writing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Character Arc Tracking$q$, $q$Dedicated sections track how each character evolves across the course of the novel.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Plot and Chapter Structure$q$, $q$Organize a novel into parts, chapters, and scenes to build a clear outline before drafting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Distraction-Focused Word Processor$q$, $q$A writer-oriented text editor with formatting tools, spell check, and dialogue-formatting shortcuts.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Story Analysis Reports$q$, $q$Generates statistics on novel length, point-of-view distribution, and character and location usage.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Mind Maps$q$, $q$Visual maps show relationships and connections between characters, locations, objects, and groups.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Cross-Platform Desktop App$q$, $q$Available for Windows, macOS, and Linux as a native desktop application.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Multi-Language Support$q$, $q$Translated into more than 15 languages according to bibisco's own materials.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Community Edition is free and fully functional for planning and writing a novel$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Structured planning tools suit writers who like to outline before drafting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Runs offline as a native desktop app, keeping manuscripts private$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Mind maps and story analysis are less common in competing writing tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$One-time payment for the Supporter Edition instead of a subscription$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Available in more than 15 languages$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Interface is less polished than some premium competitors like Scrivener$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Advanced themes and analysis features require the paid Supporter Edition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$No built-in cloud sync or real-time collaboration features$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Structured planning approach may not suit pantser writers who prefer to write without outlining first$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Desktop-only, with no official web or mobile app$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Is bibisco free?$q$, $q$Yes. The Community Edition of bibisco is free and provides a fully functional set of tools for planning and writing a novel.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$What does the Supporter Edition add?$q$, $q$The 23 euro one-time Supporter Edition adds custom themes and more advanced story analysis features on top of the free Community Edition.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Does bibisco work offline?$q$, $q$Yes. bibisco is a native desktop application that runs offline on Windows, macOS, and Linux.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Is there a Mac and Linux version of bibisco?$q$, $q$Yes. bibisco is available for Windows, macOS, and Linux.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Does bibisco support collaboration with co-authors?$q$, $q$bibisco is designed as a single-user desktop application and does not include built-in real-time collaboration features.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Can students get a discount on bibisco?$q$, $q$Yes. Students and educators can get a 20 percent discount on the Supporter Edition by emailing bibisco with valid enrollment documentation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Who created bibisco?$q$, $q$bibisco was created by Italian developer Andrea Feccomandi, who has led the project since around 2012 from Bologna, Italy.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$How is bibisco different from Scrivener?$q$, $q$bibisco is free at its core and centers on structured pre-writing planning tools like character interviews and mind maps, while Scrivener is a paid, general-purpose long-document writing tool with a broader feature set.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Multi-Book Series Planning$q$, $q$Novelists use bibisco's character and plot tools to keep details consistent across a series of books.$q$, $q$Novelists writing series fiction$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Structured Outlining$q$, $q$Writers who prefer to plan chapters, scenes, and character arcs before drafting use bibisco as their planning hub.$q$, $q$Outline-first fiction writers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Free Offline Writing Tool$q$, $q$Students and self-published authors use the free Community Edition as a private, offline alternative to paid writing software.$q$, $q$Students and self-published authors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Character development tools","Plot and chapter structure","Word processor","Mind maps","Story analysis"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$Supporter Edition$q$, $q$EUR 23$q$, $q$One-time$q$, NULL, $q$["Everything in Community Edition","Custom themes","Advanced story analysis","20% student and educator discount available"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$overview$q$, $q$What Is bibisco$q$, 2, ARRAY[$q$bibisco is a desktop novel-writing application created by Italian developer Andrea Feccomandi, who has led the project as founder since around 2012 from Bologna, Italy. It is built specifically for fiction authors who want to plan and write a novel within a single workspace.$q$, $q$Unlike a general word processor, bibisco combines a dedicated planning layer, covering characters, plot structure, and locations, with a writing-focused text editor, so authors can move between outlining and drafting in the same application.$q$, $q$The software runs on Windows, macOS, and Linux and, according to its own materials, has been downloaded more than 200,000 times and translated into more than 15 languages.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$bibisco's character tools include a structured character interview process meant to help authors develop each character in depth, along with sections for tracking how a character's arc evolves across the story.$q$, $q$For structure, authors organize their novel into parts, chapters, and scenes before writing, and can use bibisco's mind maps to visually map relationships between characters, locations, objects, and groups, which is intended to help catch plot holes and inconsistencies early.$q$, $q$A story analysis feature reports statistics on the novel's length, point-of-view distribution, and how characters and locations are used across the manuscript, while the built-in word processor includes formatting tools, spell check, and dialogue-formatting shortcuts aimed at fiction writers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('55d740dd-2254-4c1c-adfd-339116158e4d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$bibisco follows a freemium model with two editions. The Community Edition is free and provides a fully functional set of planning and writing tools for an entire novel.$q$, $q$The Supporter Edition costs 23 euros as a one-time purchase rather than a subscription, and adds custom themes along with more advanced story analysis features on top of everything in the Community Edition.$q$, $q$Students and educators can receive a 20 percent discount on the Supporter Edition by emailing bibisco with valid enrollment documentation or a school certificate.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Access to 200+ SWORD Texts$q$, $q$Connects to the CrossWire SWORD library for free access to Bibles, commentaries, dictionaries, and books in more than 50 languages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Parallel Bible View$q$, $q$Displays multiple translations or reference works side by side for comparative study.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Full-Text Search$q$, $q$Search across all installed modules to quickly find verses, terms, or topics.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Personal Notes and Highlights$q$, $q$Write, save, and organize personal study notes and highlighted passages within the app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Module Manager$q$, $q$Browse and download additional Bible texts and reference works directly from CrossWire's repositories.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Offline Study$q$, $q$Works fully offline once desired SWORD modules are downloaded and installed.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Cross-Platform Support$q$, $q$Native builds available for Linux, Windows, macOS, and FreeBSD.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Open-Source GPL Codebase$q$, $q$Source code is publicly available and licensed under the GNU General Public License.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Completely free with no ads or subscription requirements$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Large open library of Bible texts, commentaries, and dictionaries$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Works fully offline once modules are downloaded$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Actively maintained by the CrossWire open-source community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Available on Linux, Windows, and macOS$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$No account creation or sign-in required$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Interface feels dated compared to modern commercial Bible apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$No official BibleTime mobile app, though other SWORD front ends exist for mobile$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Module installation and management can be confusing for new users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Available texts depend on what CrossWire and partner societies have digitized$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Development pace is slower than well-funded commercial Bible software$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Is BibleTime free?$q$, $q$Yes. BibleTime is free, open-source software with no subscription fees or paid tiers.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$What is the SWORD Project?$q$, $q$The SWORD Project is the CrossWire Bible Society's open-source library that provides access, search, and utility functions for a large collection of digitized Bible texts, which BibleTime uses as its content engine.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$How do I add more Bible translations to BibleTime?$q$, $q$BibleTime includes a built-in module manager that lets users browse and download additional texts, commentaries, and dictionaries from CrossWire's repositories.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Does BibleTime work offline?$q$, $q$Yes. Once the desired SWORD modules are downloaded, BibleTime can be used fully offline.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Is there a BibleTime app for iPhone or Android?$q$, $q$BibleTime itself is a desktop application for Linux, Windows, and macOS; other SWORD Project front ends are built separately for mobile platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$What license does BibleTime use?$q$, $q$BibleTime is licensed under the GNU General Public License (GPL), consistent with the SWORD Project's open-source licensing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Is BibleTime open source?$q$, $q$Yes. Its source code is publicly hosted on GitHub under the BibleTime organization and licensed under the GPL.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$How many texts does BibleTime give access to?$q$, $q$Through the SWORD library, BibleTime provides access to more than 200 free texts covering more than 50 languages, including Bibles, commentaries, and dictionaries.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Comparative Bible Study$q$, $q$Students and pastors use BibleTime's parallel view and search to compare translations and commentaries side by side.$q$, $q$Pastors, students, and Bible teachers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Offline, Private Study$q$, $q$Users who want a private, ad-free, offline Bible study tool install BibleTime with locally downloaded texts.$q$, $q$Privacy-conscious readers and open-source enthusiasts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$Linux Bible Study$q$, $q$Linux users needing a native, well-integrated Bible study application choose BibleTime over web-only alternatives.$q$, $q$Linux desktop users$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$overview$q$, $q$What Is BibleTime$q$, 2, ARRAY[$q$BibleTime is a free, open-source Bible study application built in C++ with the Qt GUI toolkit. Its development dates back to at least 2006, and it remains one of the primary desktop front ends for the CrossWire Bible Society's SWORD Project.$q$, $q$Rather than shipping its own proprietary text library, BibleTime uses the SWORD library to access a shared collection of more than 200 free Bible texts, commentaries, dictionaries, and books covering more than 50 languages, maintained by CrossWire and affiliated Bible societies.$q$, $q$The application is licensed under the GNU General Public License and is available for Linux, Windows, macOS, and FreeBSD, maintained by a community of volunteer developers rather than a commercial company.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$BibleTime lets users open multiple Bible translations, commentaries, and reference books side by side for comparative study, and includes full-text search across all installed modules to locate verses, terms, or topics quickly.$q$, $q$Users can write and save personal notes and highlights directly within the application, and print or export study material as needed.$q$, $q$A built-in module manager connects to CrossWire's repositories, letting users browse, download, and install additional Bible texts, commentaries, and dictionaries directly from within BibleTime.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$BibleTime is completely free to download and use, consistent with the CrossWire Bible Society's mission of providing free, open-source Bible software.$q$, $q$There are no subscription fees, in-app purchases, or paid tiers; the application and the vast majority of texts distributed through the SWORD module system are free.$q$, $q$Because BibleTime is open source under the GPL, its source code can also be freely inspected, modified, and redistributed by anyone.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a69f323a-5bac-439b-8d2a-5a1b3804401e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$IP Geolocation API$q$, $q$Returns location data for a given IP address, including a confidence area polygon showing the realistic geographic boundary of the result.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Reverse Geocoding API$q$, $q$Converts geographic coordinates into human-readable addresses and location descriptions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Network-by-IP-Address API$q$, $q$Identifies ASN and ISP information associated with a given IP address.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$VPN, Proxy, and Tor Detection$q$, $q$Flags network-level risk signals including VPN usage, proxy connections, and Tor exit nodes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Bot Traffic Detection$q$, $q$Helps identify bot-like traffic patterns at the network level for fraud prevention use cases.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$GraphQL API Access$q$, $q$All plans include GraphQL access, letting developers request only the specific fields they need in a single query.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Patented Router-Mapping Technology$q$, $q$Uses a patented approach (US Patent No. 11,792,110 B2) that maps internet router locations to improve geolocation accuracy.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Free Tier With Full Feature Access$q$, $q$The free Base plan includes all API endpoints and fields, not a limited feature subset.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Free tier includes 10,000 requests per month with no credit card required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$All pricing tiers include every endpoint and response field$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Patented router-mapping approach aims for more transparent, accurate geolocation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Confidence area polygon gives a realistic accuracy boundary rather than a single point estimate$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$GraphQL support reduces payload size and number of API calls$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Published, transparent pricing based on monthly request volume$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Small team size may limit support responsiveness for enterprise customers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Higher-volume tiers are priced for businesses with significant request volume$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$IP-based geolocation is inherently approximate for any provider, including BigDataCloud$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Developers unfamiliar with GraphQL face a small learning curve to use it effectively$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Overage charges apply once a plan's included request volume is exceeded$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Is BigDataCloud free to use?$q$, $q$Yes. BigDataCloud offers a free Base plan covering 10,000 API requests per month with no credit card required to sign up.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$How accurate is BigDataCloud's IP geolocation?$q$, $q$BigDataCloud uses a patented approach that maps public internet routers and their service areas, and returns a confidence area polygon showing the realistic geographic boundary for each result rather than claiming a single exact point.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$What is the confidence area polygon?$q$, $q$It is a set of coordinates forming a closed polygon that represents the realistic boundary within which a given IP address is likely located, based on BigDataCloud's router service-area analysis.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Does BigDataCloud detect VPNs and proxies?$q$, $q$Yes. Its network intelligence features can flag VPN usage, proxy connections, Tor exit nodes, and bot-like traffic at the network level.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$What is included in each BigDataCloud pricing plan?$q$, $q$Every plan, from the free Base tier through Platinum, includes all API endpoints and response fields; plans differ only by monthly request volume and price.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Does BigDataCloud offer a GraphQL API?$q$, $q$Yes. All plans include GraphQL access, allowing developers to request specific fields in a single query to reduce payload size.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Where is BigDataCloud based?$q$, $q$BigDataCloud is headquartered in Adelaide, South Australia, and operates as a small, independent company.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$What is BigDataCloud's geolocation patent?$q$, $q$BigDataCloud holds a granted US patent (No. 11,792,110 B2) covering aspects of its router-mapping approach to IP geolocation.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Web App Geolocation$q$, $q$Developers use the IP Geolocation API to localize content, currency, or language based on a visitor's approximate location.$q$, $q$Web and app developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Fraud Prevention and Cybersecurity$q$, $q$Security and fraud teams use VPN, proxy, and Tor detection to flag risky sign-ups, logins, or transactions.$q$, $q$Fraud prevention and cybersecurity teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Location-Based Business Features$q$, $q$Businesses use reverse geocoding and network intelligence data to power location-based features and analytics.$q$, $q$Product and data teams building location features$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Base$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["10,000 requests per month","All endpoints and fields included","GraphQL access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Bronze$q$, $q$$29.95/month$q$, $q$Monthly$q$, NULL, $q$["100,000 requests per month","All endpoints and fields included","GraphQL access","99.999% SLA"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Silver$q$, $q$$249/month$q$, $q$Monthly$q$, NULL, $q$["1,000,000 requests per month","All endpoints and fields included","GraphQL access","99.999% SLA"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Gold$q$, $q$$1,999/month$q$, $q$Monthly$q$, NULL, $q$["10,000,000 requests per month","All endpoints and fields included","GraphQL access","99.999% SLA"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$Platinum$q$, $q$$9,999/month$q$, $q$Monthly$q$, NULL, $q$["Unlimited requests","All endpoints and fields included","GraphQL access","99.999% SLA"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$overview$q$, $q$What Is BigDataCloud$q$, 2, ARRAY[$q$BigDataCloud is an API company focused on IP geolocation, reverse geocoding, and network intelligence data. Its founders describe the idea originating in 2016, with the company formally established in 2018, and it is headquartered in Adelaide, South Australia, as a small, independent team.$q$, $q$The company's core technical approach maps the physical routing structure of the internet, identifying public router interfaces and calculating their geographic service areas from verified ground-truth data, an approach covered by a granted US patent held by BigDataCloud.$q$, $q$BigDataCloud's products are aimed at developers and businesses that need to determine where a user or IP address is located, validate contact and location data, or detect network-level risk signals such as VPNs and proxies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The flagship IP Geolocation API returns not just a location estimate but a confidence area polygon, a set of coordinates outlining the realistic geographic boundary in which a given IP address is likely operating, derived from the company's router service-area analysis.$q$, $q$Beyond geolocation, BigDataCloud offers a reverse geocoding API for converting coordinates into addresses, and a network-by-IP-address API that surfaces ASN and ISP information for a given IP.$q$, $q$Its network intelligence layer can identify VPN, proxy, Tor exit node, and bot-like traffic at the network level, and every plan, including the free tier, provides access to all endpoints and response fields along with GraphQL support for fetching only the specific fields a developer needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$BigDataCloud offers a free Base plan covering 10,000 API requests per month with no credit card required to get started, alongside four paid tiers priced by monthly request volume.$q$, $q$The Bronze plan costs 29.95 dollars per month for 100,000 requests, the Silver plan costs 249 dollars per month for 1 million requests, the Gold plan costs 1,999 dollars per month for 10 million requests, and the Platinum plan costs 9,999 dollars per month for unlimited requests.$q$, $q$All paid plans include the same full set of endpoints and fields as the free tier, GraphQL access, and a stated 99.999 percent SLA, with overage charges available for usage beyond a plan's included request volume.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9826d35d-e9bd-4d1b-ba34-0605c67a12ec', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
