-- ── BetterDiscord ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BetterDiscord is a free, open-source client modification for the Discord desktop app that adds custom themes, plugins, and interface tweaks not offered by the official client.$q$, short_description),
  pricing_model = COALESCE($q$free$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BetterDiscord: Custom Themes and Plugins for Discord$q$, seo_title),
  seo_meta_description = COALESCE($q$BetterDiscord adds free themes, plugins, and UI customization to the Discord desktop app. See features, install steps, risks, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BetterDiscord is a free, open-source client modification for the Discord desktop application that lets users install custom CSS themes and JavaScript plugins on top of the official Discord client. It was originally created by a developer known as Jiiks in August 2015. After the original project went dormant, a developer known as Zerebos forked it in October 2018 as BandagedBD to keep it maintained, and a full rewrite begun in March 2020 became the current BetterDiscord codebase that the project ships today under the BetterDiscord organization on GitHub. The tool works by injecting a loader into the local Discord app files rather than modifying Discord's servers, giving users a built-in plugin API, a live CSS editor, and support for third-party emote services such as BTTV and FFZ. Because BetterDiscord is entirely client-side and free, there is no company, pricing tier, or paid edition; the software and its themes and plugins are distributed for free through betterdiscord.app and community repositories, and the source code is publicly available on GitHub. A factual point worth noting: modifying the Discord client in this way is against Discord's Terms of Service, and Discord has stated publicly that client mods like BetterDiscord are not permitted, since they alter client behavior outside what Discord officially supports. In practice, enforcement has historically focused on accounts that use mods for abusive behavior, spam, or automation rather than banning every installation on sight, but using BetterDiscord always carries some risk of account action because it violates the ToS, and users should weigh that risk themselves rather than assume it is either completely safe or certain to cause a ban. BetterDiscord is popular mainly with power users, server moderators, and developers who want a more customizable or utility-rich chat experience than the stock Discord app provides. It requires manual installation and periodic updates to stay compatible after Discord ships client updates, and quality and safety of third-party plugins vary since they are community-submitted rather than reviewed by Discord itself.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '57e5cd5a-3371-4f98-94e6-bdba29cb1d89';

