-- ── Betterworks ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Betterworks is an enterprise performance management platform that combines OKR goal-setting, continuous feedback, performance reviews, calibration, and talent intelligence in one system.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$8/user/month (Performance plan)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Menlo Park, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Betterworks: Enterprise OKR and Performance Management$q$, seo_title),
  seo_meta_description = COALESCE($q$Betterworks combines OKRs, feedback, performance reviews, and talent intelligence for enterprises. See features, pricing, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Betterworks is an enterprise performance management and talent intelligence software platform founded in 2013 and headquartered in Menlo Park, California, with an additional office in New York City. The company was co-founded by Kris Duggan, who served as founding CEO before stepping away from day-to-day leadership in 2017. Betterworks raised venture funding from investors including Kleiner Perkins and Emergence Capital, totaling roughly 40 million dollars across its early funding rounds. The platform's core offering combines goal and OKR (objectives and key results) management with continuous feedback, structured performance reviews, calibration workflows, succession planning, skills intelligence, and AI-assisted coaching and workforce insights, positioning it as a connected performance and talent system rather than a single-purpose OKR tool. Betterworks sells three main plans: Performance, priced at 8 dollars per user per month, which covers goal and OKR tracking, feedback, review conversations, and manager 1-on-1 tools; Performance plus Talent Intelligence, priced at 9 dollars per user per month, which adds calibration, succession planning, skills intelligence, and unified talent profiles; and a custom-priced Enterprise tier that adds transformational program design, engagement and culture measurement, and a dedicated implementation team. Betterworks does not offer self-serve signup, and the company positions its platform primarily for organizations of 500 or more employees, making it best suited to mid-market and large enterprises rather than small teams. Current estimates place Betterworks at roughly 160 to 220 employees as of 2026, depending on the data source. The platform integrates with common workplace tools such as Slack, Microsoft Teams, and HRIS systems, and it competes with other performance management and OKR platforms such as Lattice, Culture Amp, and 15Five.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '25a76d30-e9e5-4707-ae76-35af527f1879';

