-- ── Bevy Engine ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bevy is a free, open-source, data-driven game engine built in Rust, known for its fast Entity Component System (ECS) architecture and modular plugin design.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bevy Engine: Free Open-Source Rust Game Engine$q$, seo_title),
  seo_meta_description = COALESCE($q$Bevy is a free, open-source Rust game engine with a fast ECS architecture. See features, pricing, pros and cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bevy is a free and open-source game engine and application framework written in the Rust programming language. It was created by Carter Anderson, a former Microsoft software engineer, with early development starting around January 2020 and a first public announcement and release, version 0.1, on August 10, 2020. Bevy is built around a data-driven Entity Component System (ECS) architecture, in which entities are simple identifiers, components are plain data attached to those entities, and systems are functions that operate on components, allowing the engine's scheduler to run many systems in parallel for performance. The engine includes modern 2D and 3D rendering with support for sprites, cameras, lights, shadows, and glTF assets, a Bevy UI framework built on ECS principles with a flexbox-style layout model, hot-reloading of assets during development, and cross-platform support for Windows, macOS, Linux, and the web via WebAssembly. Bevy is dual-licensed under the MIT and Apache 2.0 licenses, meaning developers can choose either license and use the engine free of charge, including for commercial games, with no royalties or revenue-sharing requirements. As of the engine's ongoing development, Bevy has not yet reached a 1.0 release, and its API has continued to change between minor versions, which developers should account for when starting new projects. Development is coordinated through the open-source GitHub repository under the bevyengine organization, with contributions from a large community of volunteers, and is financially supported in part by the nonprofit Bevy Foundation, established to help fund ongoing engine development. Bevy has become one of the most widely used Rust game engines, frequently compared to alternatives such as Macroquad, ggez, and Fyrox, and is popular with developers who want a modern ECS-based architecture and the performance and memory-safety characteristics of Rust.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd53fd227-dfc9-4433-b23c-eae93cde107f';

