-- ── Bexi ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Bexi was a San Francisco-based design-subscription platform that gave marketing teams on-demand access to a creative production team for video, digital ads, and web design work.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Bexi: Design Subscription Platform for Marketing Teams$q$, seo_title),
  seo_meta_description = COALESCE($q$Bexi offered points-based design subscriptions for marketing teams needing video, ad, and web design work without hiring in-house.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Bexi was launched in August 2016 by Rafael Gomez and Cuco Vega and was based in San Francisco, with additional production offices in Mexico, including Guadalajara, Mexico City, and La Paz. It operated as a design-subscription and creative-operations platform aimed at marketing teams that needed a steady stream of design output, such as video content, digital advertisements, and website design, without hiring additional in-house designers or paying traditional agency rates. Bexi's model was built around monthly or annual subscription plans that granted customers a pool of points, redeemable for standard or premium design assets and managed through a dedicated account manager who helped clients prioritize and open projects; unused points rolled over to the following month. Two plan tiers referenced in public sources were called Flexi 10 and Flexi 40 Plus, aimed respectively at customers needing a steady but modest volume of assets for one product or offering, and customers managing a higher volume of campaigns across multiple products or brands. According to third-party company data sources, Bexi reported around 1.3 million dollars in revenue with a roughly 10-person team as of 2023, and received investment from Magma Partners. As of this research, however, the bexi.io domain redirects to an unrelated personal website rather than showing an active product or marketing site, and a pricing page on the same domain displays only unpopulated template text, which suggests the original Bexi platform as described here may no longer be operating in its previous form, or that the company's web presence has changed. Because independent, current confirmation of Bexi's operating status was not found, this summary should be read as a description of the historical Bexi design-subscription business based on the information available, not a claim about its present-day availability. Prospective customers or researchers should verify current status directly before relying on Bexi as an active vendor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6a41e74d-6972-4d0c-b2ac-9bc51b258ef6';

