-- ── bibisco ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$bibisco is novel-writing software that helps fiction authors organize characters, plot, chapters, scenes, and locations in a single desktop writing workspace.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition)$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Bologna, Italy$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$bibisco: Novel Writing Software for Fiction Authors$q$, seo_title),
  seo_meta_description = COALESCE($q$bibisco helps novelists plan characters, plot, and chapters in a free desktop app. See features, pricing, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$bibisco is novel-writing software created by Italian developer Andrea Feccomandi, who has worked on the project as founder since around 2012 and is based in Bologna, Italy. It is a desktop application, available for Windows, macOS, and Linux, designed specifically for planning and writing long-form fiction such as novels. The software organizes a project around several core planning tools: a character development section that uses a structured character interview approach and tracks character arcs over the course of the story, a plot and structure tool for organizing a novel into parts, chapters, and scenes before drafting begins, a distraction-focused word processor with formatting and spell-check tailored to fiction writing, a story analysis feature that reports statistics on novel length, point-of-view distribution, and character and location usage, and mind maps that visually show relationships and connections between characters, locations, objects, and groups to help authors catch plot holes. bibisco is distributed under a freemium model: the Community Edition is free and fully functional for planning and writing a novel, while the Supporter Edition costs 23 euros as a one-time purchase and adds custom themes and more advanced analysis features; a 20 percent discount is available for students and educators who provide enrollment documentation. According to bibisco's own materials, the software has been downloaded more than 200,000 times and has been translated into more than 15 languages. bibisco is commonly compared to other novel-planning and writing tools such as Scrivener, though it is distinguished by being free at its core, open in its development approach, and built specifically around structured pre-writing planning tools like character interviews and mind maps rather than functioning primarily as a general-purpose long-document word processor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '55d740dd-2254-4c1c-adfd-339116158e4d';

