-- ── BibleTime ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BibleTime is a free, open-source Bible study application built on the CrossWire SWORD Project library, offering Bibles, commentaries, dictionaries, and books for Linux, Windows, and macOS.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BibleTime: Free Open-Source Bible Study Software$q$, seo_title),
  seo_meta_description = COALESCE($q$BibleTime is a free, open-source Bible study app built on the SWORD Project. Access 200+ texts on Linux, Windows, and macOS.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BibleTime is a free, open-source Bible study application written in C++ using the Qt GUI toolkit, with development tracing back to at least 2006. It is built on top of the SWORD Project, a cross-platform library maintained by the CrossWire Bible Society that provides programmatic access, search, and utility functions for a large collection of digitized Bible texts, commentaries, dictionaries, and other reference books. Through the SWORD library, BibleTime gives users access to more than 200 free texts covering more than 50 languages, including public-domain and freely licensed Bible translations, commentaries, and lexicons distributed by CrossWire and affiliated Bible societies. The application is licensed under the GNU General Public License (GPL), consistent with the SWORD Project's own open-source licensing, and is available as a native desktop program for Linux, Windows, and macOS, as well as FreeBSD. Core features include a parallel view for comparing multiple Bible translations side by side, full-text search across installed modules, the ability to write and save personal notes and highlights, and a built-in module manager for browsing and downloading additional texts directly from CrossWire's repositories. Because BibleTime works with locally downloaded SWORD modules, it can be used fully offline once the desired texts have been installed. BibleTime is maintained by a community of volunteer developers affiliated with the CrossWire Bible Society rather than a commercial company, and its source code is hosted publicly on GitHub under the BibleTime organization. It is one of several SWORD Project front-end applications, alongside others built for different platforms, all sharing the same underlying library and module ecosystem.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'a69f323a-5bac-439b-8d2a-5a1b3804401e';

