-- ── BigDataCloud ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BigDataCloud is an Adelaide, Australia-based API provider offering IP geolocation, reverse geocoding, and network intelligence data for developers and businesses.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (10,000 requests/month)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$1-10 employees$q$, company_size),
  headquarters = COALESCE($q$Adelaide, South Australia, Australia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BigDataCloud: IP Geolocation and Network Intelligence API$q$, seo_title),
  seo_meta_description = COALESCE($q$BigDataCloud offers IP geolocation, reverse geocoding, and network intelligence APIs with a free tier and usage-based paid plans.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BigDataCloud is an API provider specializing in IP geolocation, reverse geocoding, and network intelligence data. The company describes its idea as originating in 2016 among founders with backgrounds in network engineering, e-commerce, and fraud prevention, and it was formally established in 2018. BigDataCloud is a small, independent company headquartered in Adelaide, South Australia, with an estimated 1 to 10 employees according to public company data sources. Its core product maps the physical routing structure of the internet, identifying and categorizing public router interfaces and calculating their geographic service areas using verified ground-truth data; the company holds a granted US patent (No. 11,792,110 B2) covering aspects of this router-based geolocation approach. The flagship IP Geolocation API returns location data alongside a confidence area polygon, a set of coordinates representing the realistic geographic boundary within which a given IP address is likely operating, which the company positions as more transparent than services that return only a single point estimate. Related products include a reverse geocoding API and a network-by-IP-address API that identifies ASN and ISP information, and a network intelligence layer that can flag VPNs, proxies, Tor exit nodes, and bot-like traffic. BigDataCloud publishes tiered pricing based on monthly request volume: a free Base plan covering 10,000 requests per month, a Bronze plan at 29.95 dollars per month for 100,000 requests, a Silver plan at 249 dollars per month for 1 million requests, a Gold plan at 1,999 dollars per month for 10 million requests, and a Platinum plan at 9,999 dollars per month for unlimited requests, with overage charges available beyond each plan's included volume. All plans, including the free tier, include access to every API endpoint and response field, GraphQL access, and a stated 99.999 percent uptime SLA on paid plans. The company positions itself as a developer-focused alternative to larger IP intelligence vendors, emphasizing accuracy, transparent pricing, and broad access to functionality across all pricing tiers rather than gating specific fields or endpoints behind higher-priced plans.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9826d35d-e9bd-4d1b-ba34-0605c67a12ec';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '9826d35d-e9bd-4d1b-ba34-0605c67a12ec' AND logo IS NULL AND website IS NOT NULL;

